$reactions=$showReactions?\Kovcheg\DB::all('SELECT mr.emoji,COUNT(*) count,MAX(CASE WHEN mr.user_id=? THEN 1 ELSE 0 END) mine FROM message_reactions mr WHERE mr.message_id=? GROUP BY mr.emoji ORDER BY MIN(mr.id)',[\Kovcheg\Auth::id(),(int)$m['id']]):[];
