?>
<article id="m<?=(int)$m['id']?>" class="message message-type-<?=e((string)($m['type']??'text'))?> <?=$isMine?'mine':''?> <?=$threadMode?'thread-message':''?>" data-message-id="<?=(int)$m['id']?>" data-sender-id="<?=(int)$m['sender_id']?>" data-message-body="<?=e($plainBody)?>" data-message-author="<?=e($m['display_name']??'')?>" data-message-username="<?=e($username)?>" data-message-profile-url="<?=e($username!==''?user_public_url($username):'')?>" data-message-date="<?=e(!empty($m['created_at'])?date('d.m.Y H:i',strtotime((string)$m['created_at'])):'')?>" data-message-important="<?=message_is_important((int)$m['id'],\Kovcheg\Auth::id())?'1':'0'?>" data-thread-mode="<?=$threadMode?'1':'0'?>">
 <button type="button" class="message-select-control" data-message-select="<?=(int)$m['id']?>" aria-label="Выбрать сообщение"><span></span></button>
