  <?php if(!empty($m['forwarded_from_id'])):$fwdUser=(string)($m['forwarded_from_username']??'');?><div class="forwarded-label">Переслано от <?php if($fwdUser!==''):?><a href="<?=e(user_public_url($fwdUser))?>"><?=e($m['forwarded_from_name']??'пользователя')?></a><?php else:?><?=e($m['forwarded_from_name']??'пользователя')?><?php endif;?><?php if(!empty($m['forwarded_from_created_at'])):?><time><?=e(date('d.m.Y H:i',strtotime((string)$m['forwarded_from_created_at'])))?></time><?php endif;?></div><?php endif;?>
  <?php if(($m['type']??'')==='post'&&!empty($m['shared_post_id'])):$shared=profile_post_share_data((int)$m['shared_post_id']);$sharedFull=$shared?profile_post_for_render((int)$m['shared_post_id']):null;?>
   <?php if($shared):$sharedImage=array_values(array_filter($shared['attachments']??[],fn($a)=>str_starts_with((string)($a['mime_type']??''),'image/')))[0]??null;?><button type="button" class="message-shared-post" data-shared-post-open="<?=(int)$shared['id']?>" aria-label="Открыть запись"><header><?=avatar_html(['id'=>$shared['author_id'],'display_name'=>$shared['author_name'],'avatar_path'=>$shared['avatar_path']??null],'avatar-xs')?><span><b><?=e($shared['author_name'])?></b><small>запись на стене</small></span></header><?php if(trim((string)$shared['body'])!==''):?><p><?=e(utf8_substr(trim(strip_tags((string)$shared['body'])),0,360))?></p><?php endif;?><?php if($sharedImage):?><img src="<?=e($sharedImage['url'])?>" alt="Фотография публикации" loading="lazy"><?php endif;?></button><?php if($sharedFull):?><template data-shared-post-template="<?=(int)$shared['id']?>"><?=\Kovcheg\View::partial('feed-post',['post'=>$sharedFull])?></template><?php endif;?><?php else:?><div class="message-body">Публикация недоступна.</div><?php endif;?>
