  <?php elseif($m['type']==='sticker'&&str_starts_with((string)$m['sticker_code'],'sticker:')):$sid=(int)substr((string)$m['sticker_code'],8);?><img class="custom-sticker" src="<?=e(app_url('/sticker/'.$sid))?>" alt="Стикер">
