   <?php else:?><a class="file-card" href="<?=e(app_url('/download/'.$m['attachment_id']))?>"><span>📎</span><span><b><?=e($m['original_name'])?></b><small><?=e(format_bytes((int)$m['file_size']))?></small></span></a><?php endif;?>
   <?php if(trim($plainBody)!==''):?><div class="message-body attachment-caption"><?=safe_message_html($plainBody)?></div><?php endif;?>
  <?php else:?><?php if(trim($plainBody)!==''):?><div class="message-body"><?=safe_message_html($plainBody)?></div><?php endif;?><?php endif;?>
