   <div class="message-action-menu" data-message-action-menu role="menu" hidden>
    <?php if(!$threadMode):?><button type="button" data-reply role="menuitem"><span>↩</span>Ответить</button><?php endif;?>
    <?php if($showReactions):?><button type="button" data-reaction-menu role="menuitem"><span>♡</span>Реакция</button><?php endif;?>
    <?php if(empty($m['content_protection'])&&!$threadMode):?><button type="button" data-forward role="menuitem"><span>↗</span>Переслать</button><?php endif;?>
    <button type="button" data-message-copy role="menuitem"><span>⧉</span>Копировать</button>
    <?php if(($isMine&&can_do('can_edit_messages'))||!empty($moderation['edit'])):?><button type="button" data-edit role="menuitem"><span>✎</span>Изменить</button><?php endif;?>
    <?php if(message_can_delete_now($m,!empty($moderation['delete']))):?><button type="button" class="danger" data-delete role="menuitem"><span>⌫</span>Удалить</button><?php endif;?>
   </div>
  </div>
  <?php if($showReactions):?><div class="reaction-menu reaction-menu-modern" hidden><div class="reaction-primary"><?php foreach(['👍','❤️','🔥','😂','😮','😢','👏','🎉'] as $emoji):?><button type="button" data-message-react-modern="<?=e($emoji)?>"><?=e($emoji)?></button><?php endforeach;?><button type="button" data-reaction-more aria-label="Больше реакций">•••</button></div><div class="reaction-more-grid" hidden><?php foreach(['😁','🤣','😍','🥰','😘','🤩','🥳','🤔','🤯','😡','🤬','🙏','💪','👌','🤝','🙌','💯','⚡','⭐','🎯','✅','❌','👀','🤗'] as $emoji):?><button type="button" data-message-react-modern="<?=e($emoji)?>"><?=e($emoji)?></button><?php endforeach;?></div></div><div class="reactions"><?php foreach($reactions as $reaction):?><button type="button" class="<?=!empty($reaction['mine'])?'mine':''?>" data-react="<?=e($reaction['emoji'])?>"><?=e($reaction['emoji'])?> <span><?=e($reaction['count'])?></span></button><?php endforeach;?></div><?php endif;?>
  <?php if(!$threadMode&&!$postViewerMode&&($m['chat_type']??'')==='channel'&&!empty($m['comments_enabled'])):$postChat=['id'=>(int)$m['chat_id'],'username'=>(string)($m['chat_username']??'')];if($postChat['username']==='')$postChat['username']=(string)(\Kovcheg\DB::one('SELECT username FROM chats WHERE id=?',[$postChat['id']])['username']??'');?><a class="comments-link" href="<?=e(channel_post_public_url($postChat,(int)$m['id']))?>">💬 <span><?=((int)($m['comments_count']??0)>0)?((int)$m['comments_count'].' комментариев'):'Комментировать'?></span></a><?php endif;?>
  <?php if(!empty($m['edited_at'])):?><small class="edited">изменено</small><?php endif;?>
 </div>
